var body = $input.first().json;
var extracted = body.extracted;
if (typeof extracted === 'string') {
  try { extracted = JSON.parse(extracted); } catch(e) { extracted = {}; }
}

var now = new Date();
var pad = function(n) { return String(n).padStart(2, '0'); };
var proposalNo = 'SR-' + now.getFullYear() + pad(now.getMonth()+1) + pad(now.getDate()) + '-' + pad(now.getHours()) + pad(now.getMinutes());

var fmt = function(n) {
  if (!n) return 'TBD';
  if (n >= 1000000000) return 'Rp ' + (n/1000000000).toFixed(1) + ' M';
  if (n >= 1000000) return 'Rp ' + Math.round(n/1000000) + ' jt';
  return new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',minimumFractionDigits:0}).format(n);
};
var fmtFull = function(n) {
  if (!n) return 'TBD';
  return new Intl.NumberFormat('id-ID',{style:'currency',currency:'IDR',minimumFractionDigits:0}).format(n);
};

var rabAvg = body.rabAvg || 0;
var feeAvg = body.feeAvg || (rabAvg * 0.07);
var ppn = feeAvg * 0.11;
var totalFee = feeAvg + ppn;
var dp30 = totalFee * 0.30;
var prog40 = totalFee * 0.40;
var final30 = totalFee * 0.30;

var buildingType = (extracted.building_type || body.buildingType || 'Bangunan');
var tier = (extracted.tier || body.tier || 'Standar');
var area = extracted.area_sqm || body.areaSqm || 100;
var serviceType = (extracted.service_type || body.serviceCategory || 'Arsitektur');

var dateOpts = {day:'numeric',month:'long',year:'numeric'};
var validDate = new Date(now.getTime() + 14*24*60*60*1000);

return [{
  json: {
    from: body.from,
    clientName: body.clientName || 'Bapak/Ibu',
    phoneNumberId: body.phoneNumberId || '1052743247932102',
    proposalNo: proposalNo,
    buildingType: buildingType,
    tier: tier,
    area: area,
    serviceType: serviceType,
    rabAvg: rabAvg, rabFmt: fmt(rabAvg),
    feeAvg: feeAvg, feeFmt: fmt(feeAvg), feeFmtFull: fmtFull(feeAvg),
    ppn: ppn, ppnFmt: fmt(ppn), ppnFmtFull: fmtFull(ppn),
    totalFee: totalFee, totalFeeFmt: fmt(totalFee), totalFeeFmtFull: fmtFull(totalFee),
    dp30Fmt: fmtFull(dp30), prog40Fmt: fmtFull(prog40), final30Fmt: fmtFull(final30),
    dateFormatted: now.toLocaleDateString('id-ID', dateOpts),
    validUntil: validDate.toLocaleDateString('id-ID', dateOpts)
  }
}];

var d = $json;
var html = '<!DOCTYPE html><html lang="id"><head><meta charset="UTF-8"><style>* { margin: 0; padding: 0; box-sizing: border-box; } body { font-family: Arial, sans-serif; font-size: 13px; color: #1a1a1a; } .page { padding: 48px; max-width: 800px; margin: 0 auto; } .header { display: flex; justify-content: space-between; padding-bottom: 24px; border-bottom: 3px solid #1a1a1a; margin-bottom: 32px; } .brand h1 { font-size: 24px; font-weight: 900; } .brand p { font-size: 12px; color: #666; } .info { text-align: right; font-size: 12px; color: #666; } .client-box { background: #f5f5f5; border-left: 4px solid #1a1a1a; padding: 16px 20px; margin-bottom: 32px; } .section { margin-bottom: 28px; } .section-title { font-size: 11px; text-transform: uppercase; letter-spacing: 0.8px; color: #888; margin-bottom: 12px; padding-bottom: 8px; border-bottom: 1px solid #e0e0e0; } table { width: 100%; border-collapse: collapse; } th { background: #1a1a1a; color: white; padding: 10px 12px; text-align: left; font-size: 11px; text-transform: uppercase; } td { padding: 10px 12px; border-bottom: 1px solid #eee; } .td-right { text-align: right; font-family: monospace; } .row-grand td { background: #1a1a1a; color: white; font-weight: 700; } .payment-grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; } .payment-item { background: #f5f5f5; padding: 16px; border-radius: 4px; text-align: center; } .pct { font-size: 24px; font-weight: 900; } .amount { font-size: 12px; font-weight: 600; } .tl-item { display: flex; gap: 12px; margin-bottom: 8px; } .tl-dot { width: 8px; height: 8px; border-radius: 50%; background: #1a1a1a; margin-top: 5px; flex-shrink: 0; } .terms-list { list-style: none; } .terms-list li { padding: 4px 0 4px 16px; position: relative; font-size: 12px; color: #444; } .terms-list li::before { content: "\2014"; position: absolute; left: 0; color: #999; } .footer { margin-top: 48px; padding-top: 24px; border-top: 1px solid #e0e0e0; display: flex; justify-content: space-between; } .signature { text-align: center; } .sig-line { width: 160px; border-bottom: 1px solid #1a1a1a; margin: 40px auto 8px; }</style></head><body><div class="page">';
html += '<div class="header"><div class="brand"><h1>Sudut Ruang</h1><p>Jasa Desain Arsitektur &amp; Interior</p></div><div class="info"><div>No. Proposal</div><strong>' + d.proposalNo + '</strong><div>' + d.dateFormatted + '</div></div></div>';
html += '<h2 style="margin-bottom:8px">Proposal Jasa Desain ' + d.buildingType + '</h2>';
html += '<p style="color:#555;margin-bottom:32px">Estimasi biaya jasa desain ' + d.serviceType.toLowerCase() + ' - ' + d.tier + '</p>';
html += '<div class="client-box"><div style="font-size:10px;color:#888;text-transform:uppercase">Dipersiapkan untuk</div><strong style="font-size:14px">' + d.clientName + '</strong></div>';
html += '<div class="section"><div class="section-title">Lingkup Proyek</div><table><tr><th>Item</th><th>Detail</th></tr><tr><td>Tipe Bangunan</td><td>' + d.buildingType + ' - ' + d.tier + '</td></tr><tr><td>Luas Area</td><td>' + d.area + ' m2</td></tr><tr><td>Jenis Jasa</td><td>Desain ' + d.serviceType + '</td></tr><tr><td>Estimasi RAB Konstruksi</td><td class="td-right">' + d.rabFmt + '</td></tr></table></div>';
html += '<div class="section"><div class="section-title">Rincian Biaya Jasa Desain</div><table><tr><th>Komponen</th><th style="text-align:right">Jumlah</th></tr><tr><td>Fee Jasa Desain</td><td class="td-right">' + d.feeFmtFull + '</td></tr><tr><td>PPN 11%</td><td class="td-right">' + d.ppnFmtFull + '</td></tr><tr class="row-grand"><td>Total Tagihan</td><td class="td-right">' + d.totalFeeFmtFull + '</td></tr></table><p style="margin-top:10px;font-size:11px;color:#888">* Biaya konstruksi (RAB) terpisah dari fee jasa desain.</p></div>';
html += '<div class="section"><div class="section-title">Termin Pembayaran</div><div class="payment-grid"><div class="payment-item"><div class="pct">30%</div><div>Down Payment</div><div class="amount">' + d.dp30Fmt + '</div><div style="font-size:11px;color:#999">Saat kontrak ditandatangani</div></div><div class="payment-item"><div class="pct">40%</div><div>Progress Payment</div><div class="amount">' + d.prog40Fmt + '</div><div style="font-size:11px;color:#999">Saat gambar desain selesai</div></div><div class="payment-item"><div class="pct">30%</div><div>Final Payment</div><div class="amount">' + d.final30Fmt + '</div><div style="font-size:11px;color:#999">Saat dokumen diserahkan</div></div></div></div>';
html += '<div class="section"><div class="section-title">Estimasi Timeline</div><div class="tl-item"><div class="tl-dot"></div><div><strong>Minggu 1-2:</strong> Konsultasi, pengukuran, dan brief desain</div></div><div class="tl-item"><div class="tl-dot"></div><div><strong>Minggu 3-4:</strong> Konsep desain &amp; presentasi awal</div></div><div class="tl-item"><div class="tl-dot"></div><div><strong>Minggu 5-6:</strong> Revisi dan finalisasi desain</div></div><div class="tl-item"><div class="tl-dot"></div><div><strong>Minggu 7-8:</strong> Penyerahan dokumen lengkap</div></div></div>';
html += '<div class="section"><div class="section-title">Ketentuan Umum</div><ul class="terms-list"><li>Proposal berlaku sampai ' + d.validUntil + '.</li><li>Harga dapat berubah mengikuti kondisi pasar material.</li><li>Revisi di luar lingkup dikenakan biaya tambahan.</li><li>Hak cipta desain milik Sudut Ruang sampai pelunasan lunas.</li><li>Perubahan lingkup harus disepakati secara tertulis.</li></ul></div>';
html += '<div class="footer"><div class="signature"><div class="sig-line"></div><div>Sudut Ruang</div><div style="font-size:11px;color:#999">Principal Architect</div></div><div class="signature"><div class="sig-line"></div><div>' + d.clientName + '</div><div style="font-size:11px;color:#999">Client</div></div></div>';
html += '</div></body></html>';

return [{ json: { ...$json, htmlContent: html } }];
